option.value:
/* Navigation/Header styles */
.navbar {
    background: linear-gradient(135deg, rgba(38, 77, 115, 0.98), rgba(28, 142, 164, 0.92));
    color: #fff;
    padding: 12px 24px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    box-shadow: 0 2px 12px rgba(20, 42, 68, 0.12);
    margin-bottom: 0;
}

.navbar-brand {
    font-size: 18px;
    font-weight: 700;
    letter-spacing: 0.5px;
    margin: 0;
}

.navbar-actions {
    display: flex;
    gap: 12px;
    align-items: center;
}

.navbar-link,
.logout-btn {
    color: rgba(255, 255, 255, 0.9);
    text-decoration: none;
    font-size: 13px;
    padding: 8px 14px;
    border-radius: 8px;
    transition: background 0.15s ease;
    border: none;
    background: transparent;
    cursor: pointer;
    font-weight: 600;
}

.navbar-link:hover,
.logout-btn:hover {
    background: rgba(255, 255, 255, 0.15);
}

.logout-btn {
    background: rgba(255, 255, 255, 0.2);
    color: #fff;
}

/* Shared dashboard UI for login destinations and feedback pages */
:root {
    --bg: #eef4fb;
    --bg-2: #f7fbff;
    --card: rgba(255, 255, 255, 0.88);
    --card-strong: #ffffff;
    --text: #17324d;
    --muted: #5f7185;
    --border: rgba(23, 50, 77, 0.10);
    --primary: #264d73;
    --primary-2: #395f88;
    --accent: #1c8ea4;
    --accent-soft: #e5f7fb;
    --success: #17865f;
    --danger: #b42318;
    --shadow: 0 18px 48px rgba(20, 42, 68, 0.10);
    --shadow-soft: 0 10px 26px rgba(20, 42, 68, 0.08);
    --radius-xl: 28px;
    --radius-lg: 22px;
    --radius-md: 16px;
}

* {
    box-sizing: border-box;
}

html, body {
    margin: 0;
    min-height: 100%;
}

body {
    font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    color: var(--text);
    background:
        radial-gradient(circle at top left, rgba(53, 127, 180, 0.18), transparent 28%),
        radial-gradient(circle at bottom right, rgba(28, 142, 164, 0.10), transparent 26%),
        linear-gradient(180deg, var(--bg), var(--bg-2));
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover {
    text-decoration: none;
}

.dashboard-shell {
    width: min(1200px, calc(100% - 32px));
    margin: 24px auto;
    display: grid;
    gap: 20px;
}

.hero {
    position: relative;
    overflow: hidden;
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    background: linear-gradient(135deg, rgba(38, 77, 115, 0.98), rgba(28, 142, 164, 0.92));
    color: #fff;
    box-shadow: var(--shadow);
    padding: 28px;
}

.hero::after {
    content: "";
    position: absolute;
    inset: auto -120px -160px auto;
    width: 320px;
    height: 320px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.12);
    filter: blur(2px);
}

.hero-kicker {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.14);
    border: 1px solid rgba(255, 255, 255, 0.20);
    font-size: 12px;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    margin-bottom: 14px;
}

.hero h1 {
    margin: 0;
    font-size: clamp(28px, 4vw, 42px);
    line-height: 1.06;
}

.hero p {
    margin: 12px 0 0;
    max-width: 68ch;
    color: rgba(255, 255, 255, 0.88);
    font-size: 16px;
    line-height: 1.6;
    text-decoration: none;
    position: relative;
    z-index: 1;
}

.hero-actions {
    margin-top: 22px;
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
}

.summary-grid,
.action-grid,
.meta-grid {
    display: grid;
    gap: 16px;
}

.summary-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
}

.action-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
}

.meta-grid {
    grid-template-columns: 1.15fr 0.85fr;
    align-items: start;
}

.panel {
    background: var(--card);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-soft);
    backdrop-filter: blur(10px);
}

.card-pad {
    padding: 22px;
}

.stat-card,
.action-card,
.info-card,
.form-card,
.table-card {
    background: var(--card-strong);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-soft);
}

.stat-card {
    padding: 18px;
}

.stat-label {
    font-size: 13px;
    color: var(--muted);
    margin-bottom: 8px;
}

.stat-value {
    font-size: 28px;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 4px;
}

.stat-note {
    font-size: 13px;
    color: var(--muted);
    line-height: 1.5;
}

.action-card {
    padding: 18px;
    display: flex;
    flex-direction: column;
    gap: 12px;
    min-height: 170px;
}

.action-title {
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 18px;
    font-weight: 700;
    margin: 0;
}

.action-icon {
    width: 46px;
    height: 46px;
    border-radius: 14px;
    background: linear-gradient(135deg, rgba(38, 77, 115, 0.10), rgba(28, 142, 164, 0.18));
    color: var(--primary);
    display: grid;
    place-items: center;
    font-size: 22px;
    flex: 0 0 auto;
}

.action-card p {
    margin: 0;
    color: var(--muted);
    line-height: 1.6;
    flex: 1;
}

.quick-links {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
}

.btn,
.link-btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    min-height: 44px;
    padding: 0 16px;
    border-radius: 14px;
    font-weight: 600;
    font-size: 14px;
    border: 1px solid transparent;
    transition: transform 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;
    cursor: pointer;
}

.btn:hover,
.link-btn:hover {
    transform: translateY(-1px);
}

.btn-primary,
.link-btn-primary {
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    color: #fff;
    box-shadow: 0 10px 24px rgba(38, 77, 115, 0.24);
}

.btn-secondary,
.link-btn-secondary {
    background: #fff;
    color: var(--primary);
    border-color: rgba(38, 77, 115, 0.16);
}

.btn-soft,
.link-btn-soft {
    background: var(--accent-soft);
    color: var(--accent);
    border-color: rgba(28, 142, 164, 0.12);
}

.btn-danger {
    background: #fff5f5;
    color: var(--danger);
    border-color: rgba(180, 35, 24, 0.14);
}

.section-title {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    margin-bottom: 16px;
}

.section-title h2 {
    margin: 0;
    font-size: 22px;
}

.section-title p {
    margin: 4px 0 0;
    color: var(--muted);
    line-height: 1.5;
}

.form-card {
    padding: 22px;
}

.form-grid {
    display: grid;
    gap: 16px;
    grid-template-columns: repeat(2, minmax(0, 1fr));
}

.form-grid .full {
    grid-column: 1 / -1;
}

.field label {
    display: block;
    margin-bottom: 8px;
    font-size: 14px;
    font-weight: 600;
    color: var(--text);
}

.field input,
.field select,
.field textarea {
    width: 100%;
    border: 1px solid rgba(23, 50, 77, 0.14);
    border-radius: 14px;
    padding: 13px 14px;
    font: inherit;
    background: rgba(255, 255, 255, 0.96);
    color: var(--text);
    outline: none;
    box-shadow: inset 0 1px 2px rgba(15, 23, 42, 0.04);
}

.field input:focus,
.field select:focus,
.field textarea:focus {
    border-color: rgba(28, 142, 164, 0.55);
    box-shadow: 0 0 0 4px rgba(28, 142, 164, 0.12);
}

.field textarea {
    min-height: 150px;
    resize: vertical;
}

.helper {
    margin-top: 8px;
    font-size: 13px;
    color: var(--muted);
    line-height: 1.5;
}

.form-actions {
    margin-top: 18px;
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
}

.badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 7px 12px;
    border-radius: 999px;
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 0.04em;
    text-transform: uppercase;
}

.badge-soft {
    background: rgba(28, 142, 164, 0.12);
    color: var(--accent);
}

.badge-green {
    background: rgba(23, 134, 95, 0.12);
    color: var(--success);
}

.badge-blue {
    background: rgba(38, 77, 115, 0.12);
    color: var(--primary);
}

.table-card {
    overflow: hidden;
}

.table-wrap {
    overflow: auto;
}

.table {
    width: 100%;
    border-collapse: collapse;
    min-width: 840px;
}

.table th,
.table td {
    padding: 14px 16px;
    text-align: left;
    vertical-align: top;
    border-bottom: 1px solid rgba(23, 50, 77, 0.08);
    font-size: 14px;
}

.table th {
    position: sticky;
    top: 0;
    background: #f4f8fc;
    z-index: 1;
    color: #35516e;
    font-size: 13px;
    letter-spacing: 0.02em;
    text-transform: uppercase;
}

.table tbody tr:hover td {
    background: rgba(38, 77, 115, 0.03);
}

.empty-state {
    padding: 28px 22px;
    text-align: center;
    color: var(--muted);
}

.footer-note {
    text-align: center;
    color: var(--muted);
    font-size: 13px;
    padding: 4px 0 12px;
}

.stack {
    display: grid;
    gap: 16px;
}

@media (max-width: 980px) {
    .summary-grid,
    .action-grid,
    .meta-grid,
    .form-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 640px) {
    .dashboard-shell {
        width: min(100%, calc(100% - 20px));
        margin: 10px auto 18px;
        gap: 14px;
    }

    .hero,
    .card-pad,
    .form-card,
    .stat-card,
    .action-card {
        padding: 18px;
    }

    .section-title {
        flex-direction: column;
        align-items: flex-start;
    }

    .btn,
    .link-btn {
        width: 100%;
    }
}

